// Hand-written SSRF policy e2e tests for WASM.
// These are NOT generated by alef — edit this file directly.
//
// WASM SSRF limitation: wasm32-unknown-unknown does not have access to tokio's
// async DNS resolver, so the SSRF pre-flight check (validate_url) cannot
// resolve hostnames before connecting. Literal IP addresses are rejected by the
// URL parser (loopback) but private-range IP enforcement via DNS is unavailable
// in the WASM target.
//
// These tests verify what the WASM binding CAN enforce: scheme validation and
// rejection of URLs that fail URL parsing. Full private-IP enforcement is
// exercised by the Rust, Python, and Node e2e suites.
//
// TODO(ssrf-parity): Re-evaluate once a wasm-compatible SSRF shim is available.

import { describe, expect, it } from "vitest";
import { scrape, createEngine } from "@kreuzberg/kreuzcrawl-wasm";

describe("ssrf", () => {
	it("ssrf_loopback_error_surfaces: loopback URL scrape returns an error (WASM may not surface ssrf_policy_violation specifically)", async () => {
		// WASM cannot perform pre-flight SSRF checks the same way native targets can.
		// This test asserts only that the call fails — the error variant may differ
		// from the native ssrf_policy_violation error.
		await expect(async () => {
			const engine = createEngine(null);
			await scrape(engine, "http://127.0.0.1:9/");
		}).rejects.toThrow();
	}, 30000);
});
